var surah041 = {
  number: 41,
  nameArabic: "Fussilat",
  nameEnglish: "Fussilat",
  meaning: "Explained in Detail",
  totalAyahs: 54,
  ayahs: [
    { number: 1, arabic: "حمٓ", transliteration: "Hameem", transliterationB: "Haa Meeem", english: "Ha Mim", romanUrdu: "Haa Meem" },
    { number: 2, arabic: "تَنزِيلٌۭ مِّنَ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ", transliteration: "Tanzeelun mina alrrahmani alrraheemi", transliterationB: "Tanzeelum Minar-Rahmaanir-Raheem", english: "A Revelation from (Allah), Most Gracious, Most Merciful", romanUrdu: "Yeh khuda e Rehman o Raheem ki taraf se nazil karda cheez hai" },
    { number: 3, arabic: "كِتَٰبٌۭ فُصِّلَتْ ءَايَٰتُهُۥ قُرْءَانًا عَرَبِيًّۭا لِّقَوْمٍۢ يَعْلَمُونَ", transliteration: "Kitabun fussilat ayatuhu quranan AAarabiyyan liqawmin yaAAlamoona", transliterationB: "Kitaabun fussilat Aayaatuhoo Qur-aanan 'Arabiyyal liqawminy ya'lamoon", english: "A Book, whereof the verses are explained in detail;- a Qur'an in Arabic, for people who understand", romanUrdu: "Ek aisi kitaab jiski aayat khoob khol kar bayan ki gayi hain, Arabi zubaan ka Quran, un logon ke liye jo ilm rakhte hain" },
    { number: 4, arabic: "بَشِيرًۭا وَنَذِيرًۭا فَأَعْرَضَ أَكْثَرُهُمْ فَهُمْ لَا يَسْمَعُونَ", transliteration: "Basheeran wanatheeran faaAArada aktharuhum fahum la yasmaAAoona", transliterationB: "Basheeranw wa nazeeran fa-a'rada aksaruhum fahum laa yasma'oon", english: "Giving good news and admonition: yet most of them turn away, and so they hear not", romanUrdu: "Basharat(khush-khabri) dene wala aur dara dene wala magar in logon mein se aksar ne issey ru-gardani ki aur woh sunkar nahin detey" },
    { number: 5, arabic: "وَقَالُوا۟ قُلُوبُنَا فِىٓ أَكِنَّةٍۢ مِّمَّا تَدْعُونَآ إِلَيْهِ وَفِىٓ ءَاذَانِنَا وَقْرٌۭ وَمِنۢ بَيْنِنَا وَبَيْنِكَ حِجَابٌۭ فَٱعْمَلْ إِنَّنَا عَٰمِلُونَ", transliteration: "Waqaloo quloobuna fee akinnatin mimma tadAAoona ilayhi wafee athanina waqrun wamin baynina wabaynika hijabun faiAAmal innana AAamiloona", transliterationB: "Wa qaaloo quloobunaa feee akinnatim mimmaa tad'oonaaa ilaihi wa feee aazaaninaa waqrunw wa mim baininaa wa bainika bijaabun fa'mal innanaa 'aamiloon", english: "They say: \"Our hearts are under veils, (concealed) from that to which thou dost invite us, and in our ears in a deafness, and between us and thee is a screen: so do thou (what thou wilt); for us, we shall do (what we will)", romanUrdu: "Kehte hain “Jis cheez ki taraf tu humein bula raha hai uske liye hamare dilon par gilaf (purde) chade huey hain, hamare kaan behrey (deaf) ho gaye hain, aur hamare aur tere darmiyaan ek hijab hayal ho gaya hai. Tu apna kaam kar, hum apna kaam kiye jayenge”" },
    { number: 6, arabic: "قُلْ إِنَّمَآ أَنَا۠ بَشَرٌۭ مِّثْلُكُمْ يُوحَىٰٓ إِلَىَّ أَنَّمَآ إِلَٰهُكُمْ إِلَٰهٌۭ وَٰحِدٌۭ فَٱسْتَقِيمُوٓا۟ إِلَيْهِ وَٱسْتَغْفِرُوهُ ۗ وَوَيْلٌۭ لِّلْمُشْرِكِينَ", transliteration: "Qul innama ana basharun mithlukum yooha ilayya annama ilahukum ilahun wahidun faistaqeemoo ilayhi waistaghfiroohu wawaylun lilmushrikeena", transliterationB: "Qul innamaaa ana basharum mislukum yoohaaa ilaiya annamaaa ilaahukum Ilaahunw Waahidun fastaqeemooo ilaihi wastagfirooh; wa wailul lil mushrikeen", english: "Say thou: \"I am but a man like you: It is revealed to me by Inspiration, that your Allah is one Allah: so stand true to Him, and ask for His Forgiveness.\" And woe to those who join gods with Allah", romanUrdu: "Aey Nabi , insey kaho, mein to ek bashar hoon tum jaisa. Mujhey wahee ke zariye se bataya jaata hai ke tumhara khuda to bas ek hi khuda hai, Lihaza tum seedhey usi ka rukh ikhtiyar karo aur ussey maafi chaho. Tabahi hai un mushrikon ke liye" },
    { number: 7, arabic: "ٱلَّذِينَ لَا يُؤْتُونَ ٱلزَّكَوٰةَ وَهُم بِٱلْءَاخِرَةِ هُمْ كَٰفِرُونَ", transliteration: "Allatheena la yutoona alzzakata wahum bialakhirati hum kafiroona", transliterationB: "Allazeena laa yu'toonaz Zakaata wa hum bil-Aakhiratihum kaafiroon", english: "Those who practise not regular Charity, and who even deny the Hereafter", romanUrdu: "Jo zakat nahin detay aur aakhirat ke munkir hain" },
    { number: 8, arabic: "إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَهُمْ أَجْرٌ غَيْرُ مَمْنُونٍۢ", transliteration: "Inna allatheena amanoo waAAamiloo alssalihati lahum ajrun ghayru mamnoonin", transliterationB: "Innal lazeena aamanoo wa 'amilus saalihaati lahum ajrun ghairu mamnoon", english: "For those who believe and work deeds of righteousness is a reward that will never fail", romanUrdu: "Rahey woh log jinhon ne maan liya aur neik aamaal kiye, unke liye yaqeenan aisa ajar hai jiska silsila kabhi tootne wala nahin hai" },
    { number: 9, arabic: "۞ قُلْ أَئِنَّكُمْ لَتَكْفُرُونَ بِٱلَّذِى خَلَقَ ٱلْأَرْضَ فِى يَوْمَيْنِ وَتَجْعَلُونَ لَهُۥٓ أَندَادًۭا ۚ ذَٰلِكَ رَبُّ ٱلْعَٰلَمِينَ", transliteration: "Qul ainnakum latakfuroona biallathee khalaqa alarda fee yawmayni watajAAaloona lahu andadan thalika rabbu alAAalameena", transliterationB: "Qul a'innakum latakfuroona billazee khalaqal arda fee yawmaini wa taj'aloona lahooo andaadaa; zaalika Rabbul 'aalameen", english: "Say: Is it that ye deny Him Who created the earth in two Days? And do ye join equals with Him? He is the Lord of (all) the Worlds", romanUrdu: "Aey Nabi! Insey kaho, kya tum us khuda se kufr karte ho aur dusron ko uska humsar (shareek / equals) thehratey ho jisne zameen ko do (two) dino mein bana diya? Wahi to saarey jahan waalon ka Rubb hai" },
    { number: 10, arabic: "وَجَعَلَ فِيهَا رَوَٰسِىَ مِن فَوْقِهَا وَبَٰرَكَ فِيهَا وَقَدَّرَ فِيهَآ أَقْوَٰتَهَا فِىٓ أَرْبَعَةِ أَيَّامٍۢ سَوَآءًۭ لِّلسَّآئِلِينَ", transliteration: "WajaAAala feeha rawasiya min fawqiha wabaraka feeha waqaddara feeha aqwataha fee arbaAAati ayyamin sawaan lilssaileena", transliterationB: "Wa ja'ala feehaa rawaa siya min fawqihaa wa baaraka feehaa wa qaddara feehaaaa aqwaatahaa feee arba'ati ayyaamin sawaaa'al lissaaa'ileen", english: "He set on the (earth), mountains standing firm, high above it, and bestowed blessings on the earth, and measure therein all things to give them nourishment in due proportion, in four Days, in accordance with (the needs of) those who seek (Sustenance)", romanUrdu: "Usne (zameen ko wajood mein laane ke baad) upar se ispar pahadh (mountains) jamaa diye aur ismein barakatein rakh di aur iske andar sab maangne waalon ke liye har ek ki talab o haajat ke mutaabiq theek andaze se khuraak ka saaman muhaiyya kardiya. Yeh sab kaam chaar (four) din mein ho gaye" },
    { number: 11, arabic: "ثُمَّ ٱسْتَوَىٰٓ إِلَى ٱلسَّمَآءِ وَهِىَ دُخَانٌۭ فَقَالَ لَهَا وَلِلْأَرْضِ ٱئْتِيَا طَوْعًا أَوْ كَرْهًۭا قَالَتَآ أَتَيْنَا طَآئِعِينَ", transliteration: "Thumma istawa ila alssamai wahiya dukhanun faqala laha walilardi itiya tawAAan aw karhan qalata atayna taiAAeena", transliterationB: "Summas tawaaa ilas-samaaa'i wa hiya dukhaanun faqaala lahaa wa lil ardi'tiyaaa taw'an aw karhan qaalataaa atainaa taaa'i'een", english: "Moreover He comprehended in His design the sky, and it had been (as) smoke: He said to it and to the earth: \"Come ye together, willingly or unwillingly.\" They said: \"We do come (together), in willing obedience", romanUrdu: "Phir woh aasmaan ki taraf mutwajjeh huwa Jo us waqt mehaz dhuwan (smoke) tha. Usne aasman aur zameen se kaha “wajood mein aa jao, khwa tum chaho ya na chaho.” Dono ne kaha “ hum aa gaye farma bardaron ki tarah”" },
    { number: 12, arabic: "فَقَضَىٰهُنَّ سَبْعَ سَمَٰوَاتٍۢ فِى يَوْمَيْنِ وَأَوْحَىٰ فِى كُلِّ سَمَآءٍ أَمْرَهَا ۚ وَزَيَّنَّا ٱلسَّمَآءَ ٱلدُّنْيَا بِمَصَٰبِيحَ وَحِفْظًۭا ۚ ذَٰلِكَ تَقْدِيرُ ٱلْعَزِيزِ ٱلْعَلِيمِ", transliteration: "Faqadahunna sabAAa samawatin fee yawmayni waawha fee kulli samain amraha wazayyanna alssamaa alddunya bimasabeeha wahifthan thalika taqdeeru alAAazeezi alAAaleemi", transliterationB: "Faqadaahunna sab'a samaawaatin fee yawmaini wa awhaa fee kulli samaaa'in amarahaa; wa zaiyannassa maaa'ad dunyaa bimasaabeeha wa hifzaa; zaalika taqdeerul 'Azeezil 'Aleem", english: "So He completed them as seven firmaments in two Days, and He assigned to each heaven its duty and command. And We adorned the lower heaven with lights, and (provided it) with guard. Such is the Decree of (Him) the Exalted in Might, Full of Knowledge", romanUrdu: "Tab usne do din ke andar saath (seven) aasmaan bana diye, aur har aasmaan mein us ka kanoon wahee (reveal) kardiya. Aur aasmaan e duniya ko humne chiraagon (lamps) se aarasta (adorn) kiya aur isey khoob mehfooz kardiya. Yeh sab kuch ek zabardast hasti ka mansooba (plan) hai" },
    { number: 13, arabic: "فَإِنْ أَعْرَضُوا۟ فَقُلْ أَنذَرْتُكُمْ صَٰعِقَةًۭ مِّثْلَ صَٰعِقَةِ عَادٍۢ وَثَمُودَ", transliteration: "Fain aAAradoo fuqul anthartukum saAAiqatan mithla saAAiqati AAadin wathamooda", transliterationB: "Fa-in a'radoo faqul anzartukum saa'iqatam misla saa'iqati 'Aadinw wa Samood", english: "But if they turn away, say thou: \"I have warned you of a stunning Punishment (as of thunder and lightning) like that which (overtook) the 'Ad and the Thamud", romanUrdu: "Ab agar yeh log mooh moadte hain to insey kehdo ke “main tumko usi tarah ke ek achanak toot padne waley azaab se darata hoon jaisa Aad aur Samood par nazil hua tha.”" },
    { number: 14, arabic: "إِذْ جَآءَتْهُمُ ٱلرُّسُلُ مِنۢ بَيْنِ أَيْدِيهِمْ وَمِنْ خَلْفِهِمْ أَلَّا تَعْبُدُوٓا۟ إِلَّا ٱللَّهَ ۖ قَالُوا۟ لَوْ شَآءَ رَبُّنَا لَأَنزَلَ مَلَٰٓئِكَةًۭ فَإِنَّا بِمَآ أُرْسِلْتُم بِهِۦ كَٰفِرُونَ", transliteration: "Ith jaathumu alrrusulu min bayni aydeehim wamin khalfihim alla taAAbudoo illa Allaha qaloo law shaa rabbuna laanzala malaikatan fainna bima orsiltum bihi kafiroona", transliterationB: "Iz jaaa'at humur Rusulu mim baini aydeehim wa min khalfihim allaa ta'budooo illal laaha qaaloo law shaaa'a Rabunaa la anzala malaaa 'ikatan fa innaa bimaaa ursiltum bihee kaafiroon", english: "Behold, the messengers came to them, from before them and behind them, (preaching): \"Serve none but Allah.\" They said, \"If our Lord had so pleased, He would certainly have sent down angels (to preach). Now we reject your mission (altogether)", romanUrdu: "Jab khuda ke Rasool unke paas aagey aur peechey, har taraf se aaye aur unhein samjhaya ke Allah ke siwa kisi ki bandagi na karo to unhon ne kaha “hamara Rubb chahta to farishte bhejta, lihaza hum us baat ko nahin maante jiske liye tum bheje gaye ho.”" },
    { number: 15, arabic: "فَأَمَّا عَادٌۭ فَٱسْتَكْبَرُوا۟ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ وَقَالُوا۟ مَنْ أَشَدُّ مِنَّا قُوَّةً ۖ أَوَلَمْ يَرَوْا۟ أَنَّ ٱللَّهَ ٱلَّذِى خَلَقَهُمْ هُوَ أَشَدُّ مِنْهُمْ قُوَّةًۭ ۖ وَكَانُوا۟ بِـَٔايَٰتِنَا يَجْحَدُونَ", transliteration: "Faamma AAadun faistakbaroo fee alardi bighayri alhaqqi waqaloo man ashaddu minna quwwatan awalam yaraw anna Allaha allathee khalaqahum huwa ashaddu minhum quwwatan wakanoo biayatina yajhadoona", transliterationB: "Fa ammaa 'Aadun fastak baroo fil ardi bighairul haqqi wa qaaloo man ashaddu minnaa quwwatan awalam yaraw annal laahal lazee khalaqahum Huwa ashaddu minhum quwwatanw wa kaanoo bi Aayaatinaa yajhadoon", english: "Now the 'Ad behaved arrogantly through the land, against (all) truth and reason, and said: \"Who is superior to us in strength?\" What! did they not see that Allah, Who created them, was superior to them in strength? But they continued to reject Our Signs", romanUrdu: "Aad ka haal yeh tha ke woh zameen mein kisi haqq ke bagair baday ban baithey aur kehne lagey: “ kaun hai humse zyada zoorawar?” Unko yeh na soojha ke jis khuda ne unko paida kiya hai woh unse zyada zoorawar hai? Woh hamari aayat ka inkaar hi karte rahey" },
    { number: 16, arabic: "فَأَرْسَلْنَا عَلَيْهِمْ رِيحًۭا صَرْصَرًۭا فِىٓ أَيَّامٍۢ نَّحِسَاتٍۢ لِّنُذِيقَهُمْ عَذَابَ ٱلْخِزْىِ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَلَعَذَابُ ٱلْءَاخِرَةِ أَخْزَىٰ ۖ وَهُمْ لَا يُنصَرُونَ", transliteration: "Faarsalna AAalayhim reehan sarsaran fee ayyamin nahisatin linutheeqahum AAathaba alkhizyi fee alhayati alddunya walaAAathabu alakhirati akhza wahum la yunsaroona", transliterationB: "Fa arsalnaa 'alaihim reehan sarsaran feee ayyaamin nahisaatil linuzeeqahum 'azaabal khizyi fil hayaatid dunyaa wa la'azaabul Aakhirati akhzaa wa hum laa yunsaroon", english: "So We sent against them a furious Wind through days of disaster, that We might give them a taste of a Penalty of humiliation in this life; but the Penalty of a Hereafter will be more humiliating still: and they will find no help", romanUrdu: "Aakhir e kaar humne chandh manhoos dino mein sakht toofaani hawa unpar bhej di taa-ke unhein duniya hi ki zindagi mein zillat o ruswayi ke azaab ka maza chakha dein.Aur aakhirat ka azaab to issey bhi zyada ruswa-kun hai. Wahan koi unki madad karne wala na hoga" },
    { number: 17, arabic: "وَأَمَّا ثَمُودُ فَهَدَيْنَٰهُمْ فَٱسْتَحَبُّوا۟ ٱلْعَمَىٰ عَلَى ٱلْهُدَىٰ فَأَخَذَتْهُمْ صَٰعِقَةُ ٱلْعَذَابِ ٱلْهُونِ بِمَا كَانُوا۟ يَكْسِبُونَ", transliteration: "Waamma thamoodu fahadaynahum faistahabboo alAAama AAala alhuda faakhathathum saAAiqatu alAAathabi alhooni bima kanoo yaksiboona", transliterationB: "Wa ammaa Samoodu fahadinaahum fastahabbul 'ama 'alal huda fa akhazathum saa'iqatul 'azaabil hooni bimaa kaanoo yaksiboon", english: "As to the Thamud, We gave them Guidance, but they preferred blindness (of heart) to Guidance: so the stunning Punishment of humiliation seized them, because of what they had earned", romanUrdu: "Rahey Samood, to unke samne humne raah e raast pesh ki magar unhon ne raasta dekhne ke bajaye andha (blind) bana rehna pasand kiya. Aakhir unke kartooton ki badaulat zillat ka azaab unpar toot pada" },
    { number: 18, arabic: "وَنَجَّيْنَا ٱلَّذِينَ ءَامَنُوا۟ وَكَانُوا۟ يَتَّقُونَ", transliteration: "Wanajjayna allatheena amanoo wakanoo yattaqoona", transliterationB: "Wa najjainal lazeena aamanoo wa kaanoo yattaqoon", english: "But We delivered those who believed and practised righteousness", romanUrdu: "Aur humne un logon ko bacha liya jo imaan laaye thay aur gumrahi o bad-amali se parheiz karte thay" },
    { number: 19, arabic: "وَيَوْمَ يُحْشَرُ أَعْدَآءُ ٱللَّهِ إِلَى ٱلنَّارِ فَهُمْ يُوزَعُونَ", transliteration: "Wayawma yuhsharu aAAdao Allahi ila alnnari fahum yoozaAAoona", transliterationB: "Wa yawma yuhsharu a'daaa'ul laahi ilan Naari fahum yooza'oon", english: "On the Day that the enemies of Allah will be gathered together to the Fire, they will be marched in ranks", romanUrdu: "Aur zara us waqt ka khayal karo jab Allah ke yeh dushman dozakh ki taraf jaane ke liye ghair laaye jayenge unke agalon ko pichlon ke aane tak roak rakkha jayega" },
    { number: 20, arabic: "حَتَّىٰٓ إِذَا مَا جَآءُوهَا شَهِدَ عَلَيْهِمْ سَمْعُهُمْ وَأَبْصَٰرُهُمْ وَجُلُودُهُم بِمَا كَانُوا۟ يَعْمَلُونَ", transliteration: "Hatta itha ma jaooha shahida AAalayhim samAAuhum waabsaruhum wajulooduhum bima kanoo yaAAmaloona", transliterationB: "Hattaaa izaa maa jaaa'oohaa shahida 'alaihim samu'uhum wa absaaruhum wa julooduhum bimaa kaanoo ya'maloon", english: "At length, when they reach the (Fire), their hearing, their sight, and their skins will bear witness against them, as to (all) their deeds", romanUrdu: "Phir jab sab wahan pahunch jayenge to unke kaan aur unki aankhein aur unke jism ki khaalein (skins) unpar gawahi dengi ke woh duniya mein kya kuch karte rahey hain" },
    { number: 21, arabic: "وَقَالُوا۟ لِجُلُودِهِمْ لِمَ شَهِدتُّمْ عَلَيْنَا ۖ قَالُوٓا۟ أَنطَقَنَا ٱللَّهُ ٱلَّذِىٓ أَنطَقَ كُلَّ شَىْءٍۢ وَهُوَ خَلَقَكُمْ أَوَّلَ مَرَّةٍۢ وَإِلَيْهِ تُرْجَعُونَ", transliteration: "Waqaloo lijuloodihim lima shahidtum AAalayna qaloo antaqana Allahu allathee antaqa kulla shayin wahuwa khalaqakum awwala marratin wailayhi turjaAAoona", transliterationB: "Wa qaaloo lijuloodihim lima shahittum 'alainaa qaaloo antaqanal laahul lazeee antaqa kulla shai'inw wa Huwa khalaqakum awwala marratinw wa ilaihi turja'oon", english: "They will say to their skins: \"Why bear ye witness against us?\" They will say: \"Allah hath given us speech,- (He) Who giveth speech to everything: He created you for the first time, and unto Him were ye to return", romanUrdu: "Woh apne jism ki khaalon se kahenge “ tumne hamare khilaf kyun gawahi di? “ woh jawab dengi “ humein usi khuda ne goyaii (speech) di hai jisne har cheez ko goya(speech) kardiya hai. Usi ne tumko pehli martaba paida kiya tha aur ab usi ki taraf tum wapas laaye ja rahey ho" },
    { number: 22, arabic: "وَمَا كُنتُمْ تَسْتَتِرُونَ أَن يَشْهَدَ عَلَيْكُمْ سَمْعُكُمْ وَلَآ أَبْصَٰرُكُمْ وَلَا جُلُودُكُمْ وَلَٰكِن ظَنَنتُمْ أَنَّ ٱللَّهَ لَا يَعْلَمُ كَثِيرًۭا مِّمَّا تَعْمَلُونَ", transliteration: "Wama kuntum tastatiroona an yashhada AAalaykum samAAukum wala absarukum wala juloodukum walakin thanantum anna Allaha la yaAAlamu katheeran mimma taAAmaloona", transliterationB: "Wa maa kuntum tastatiroona ai-yashhada 'alaikum sam'ukum wa laaa absaarukum wa laa juloodukum wa laakin zanantum annal laaha laa ya'lamu kaseeram mimmaa ta'maloon", english: "Ye did not seek to hide yourselves, lest your hearing, your sight, and your skins should bear witness against you! But ye did think that Allah knew not many of the things that ye used to do", romanUrdu: "Tum duniya mein jarahim (crime) karte waqt chupte thay to tumhein yeh khayal na tha ke kabhi tumhare apne kaan aur tumhari aankhein aur tumhare jism ki khaalein (skins) tumpar gawahi dengi balke tumne yeh samajha tha ke tumhare bahut se aamal ki Allah ko bhi khabar nahin hai" },
    { number: 23, arabic: "وَذَٰلِكُمْ ظَنُّكُمُ ٱلَّذِى ظَنَنتُم بِرَبِّكُمْ أَرْدَىٰكُمْ فَأَصْبَحْتُم مِّنَ ٱلْخَٰسِرِينَ", transliteration: "Wathalikum thannukumu allathee thanantum birabbikum ardakum faasbahtum mina alkhasireena", transliterationB: "Wa zaalikum zannukumul lazee zanantum bi-Rabbikum ardaakum fa asbahtum minal khaasireen", english: "But this thought of yours which ye did entertain concerning your Lord, hath brought you to destruction, and (now) have ye become of those utterly lost", romanUrdu: "Tumhara yahi gumaan jo tumne apne Rubb ke saath kiya tha, tumhein ley dooba aur isi ki badaulat tum khasare(loss) mein padh gaye”" },
    { number: 24, arabic: "فَإِن يَصْبِرُوا۟ فَٱلنَّارُ مَثْوًۭى لَّهُمْ ۖ وَإِن يَسْتَعْتِبُوا۟ فَمَا هُم مِّنَ ٱلْمُعْتَبِينَ", transliteration: "Fain yasbiroo faalnnaru mathwan lahum wain yastaAAtiboo fama hum mina almuAAtabeena", transliterationB: "Fa-iny yasbiroo fan Naaru maswal lahum wa iny-yasta'tiboo famaa hum minal mu'tabeen", english: "If, then, they have patience, the Fire will be a home for them! and if they beg to be received into favour, into favour will they not (then) be received", romanUrdu: "Is halat mein woh sabr karein (ya na karein) aag hi unka thikana hogi, aur agar rujoo ka mauqa chahenge to koi mauqa unhein na diya jayega" },
    { number: 25, arabic: "۞ وَقَيَّضْنَا لَهُمْ قُرَنَآءَ فَزَيَّنُوا۟ لَهُم مَّا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ وَحَقَّ عَلَيْهِمُ ٱلْقَوْلُ فِىٓ أُمَمٍۢ قَدْ خَلَتْ مِن قَبْلِهِم مِّنَ ٱلْجِنِّ وَٱلْإِنسِ ۖ إِنَّهُمْ كَانُوا۟ خَٰسِرِينَ", transliteration: "Waqayyadna lahum quranaa fazayyanoo lahum ma bayna aydeehim wama khalfahum wahaqqa AAalayhimu alqawlu fee omamin qad khalat min qablihim mina aljinni waalinsi innahum kanoo khasireena", transliterationB: "Wa qaiyadnaa lahum quranaaa'a fazaiyanoo lahum maa baina aideehim wa maa khalfahum wa haqqa 'alaihimul qawlu feee umamin qad khalat min qablihim minal jinni wal insi innahum kaanoo khaasireen", english: "And We have destined for them intimate companions (of like nature), who made alluring to them what was before them and behind them; and the sentence among the previous generations of Jinns and men, who have passed away, is proved against them; for they are utterly lost", romanUrdu: "Humne unpar aisey saathi musallat kardiye thay jo unhein aagey aur peechey har cheez khushnuma banakar dikhate thay. Aakhir e kaar unpar bhi wahi faisla e azaab chaspan ho kar raha jo un se pehle guzray huey Jinno aur Insano ke girohon par chaspan ho chuka tha, yaqeenan woh khasare (loss) mein reh jaane waley thay" },
    { number: 26, arabic: "وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَا تَسْمَعُوا۟ لِهَٰذَا ٱلْقُرْءَانِ وَٱلْغَوْا۟ فِيهِ لَعَلَّكُمْ تَغْلِبُونَ", transliteration: "Waqala allatheena kafaroo la tasmaAAoo lihatha alqurani wailghaw feehi laAAallakum taghliboona", transliterationB: "Wa qaalal lazeena kafaroo laa tasma'oo lihaazal Quraani walghaw feehi la'allakum taghlihoon", english: "The Unbelievers say: \"Listen not to this Qur'an, but talk at random in the midst of its (reading), that ye may gain the upper hand", romanUrdu: "Yeh munkireen e haqq kehte hain “is Quran ko hargiz na sunoo aur jab yeh sunaya jaye to ismein khalal daalo, shayad ke is tarah tum gaalib aa jao”" },
    { number: 27, arabic: "فَلَنُذِيقَنَّ ٱلَّذِينَ كَفَرُوا۟ عَذَابًۭا شَدِيدًۭا وَلَنَجْزِيَنَّهُمْ أَسْوَأَ ٱلَّذِى كَانُوا۟ يَعْمَلُونَ", transliteration: "Falanutheeqanna allatheena kafaroo AAathaban shadeedan walanajziyannahum aswaa allathee kanoo yaAAmaloona", transliterationB: "Falanuzeeqannal lazeena kafaroo 'azaaban shadeedanw wa lanajziyannahum aswallazee kaanoo ya'maloon", english: "But We will certainly give the Unbelievers a taste of a severe Penalty, and We will requite them for the worst of their deeds", romanUrdu: "In kaafiron ko hum sakht azaab ka maza chakha kar rahenge aur jo badhtareen harakaat yeh karte rahey hain unka poora poora badla inhein dengey" },
    { number: 28, arabic: "ذَٰلِكَ جَزَآءُ أَعْدَآءِ ٱللَّهِ ٱلنَّارُ ۖ لَهُمْ فِيهَا دَارُ ٱلْخُلْدِ ۖ جَزَآءًۢ بِمَا كَانُوا۟ بِـَٔايَٰتِنَا يَجْحَدُونَ", transliteration: "Thalika jazao aAAdai Allahi alnnaru lahum feeha daru alkhuldi jazaan bima kanoo biayatina yajhadoona", transliterationB: "Zaalika jazaaa'u a'daaa'il laahin Naaru lahum feehaa daarul khuld, jazaaa'am bimaa kaanoo bi aayaatinaa yajhdoon", english: "Such is the requital of the enemies of Allah,- the Fire: therein will be for them the Eternal Home: a (fit) requital, for that they were wont to reject Our Signs", romanUrdu: "Woh dozakh hai jo Allah ke dushmano ko badley mein milegi, usi mein hamesha hamesha ke liye inka ghar hoga. Yeh hai saza is jurm ki ke woh hamari aayat ka inkar karte rahey" },
    { number: 29, arabic: "وَقَالَ ٱلَّذِينَ كَفَرُوا۟ رَبَّنَآ أَرِنَا ٱلَّذَيْنِ أَضَلَّانَا مِنَ ٱلْجِنِّ وَٱلْإِنسِ نَجْعَلْهُمَا تَحْتَ أَقْدَامِنَا لِيَكُونَا مِنَ ٱلْأَسْفَلِينَ", transliteration: "Waqala allatheena kafaroo rabbana arina allathayni adallana mina aljinni waalinsi najAAalhuma tahta aqdamina liyakoona mina alasfaleena", transliterationB: "Wa qaalal lazeena kafaroo Rabbanaaa arinal lazaini adal laanaa minal jinni wal insi naj'alhumaa tahta aqdaaminaa liyakoonaa minal asfaleen", english: "And the Unbelievers will say: \"Our Lord! Show us those, among Jinns and men, who misled us: We shall crush them beneath our feet, so that they become the vilest (before all)", romanUrdu: "Wahan yeh kaafir kahenge ke “ aey hamare Rubb, zara humein dikha de un Jinno aur Insano ko jinhon ne humein gumraah kiya tha, hum unhein paon (legs) taley roondh daalein taa-ke woh khoob zaleel o khwar hon.”" },
    { number: 30, arabic: "إِنَّ ٱلَّذِينَ قَالُوا۟ رَبُّنَا ٱللَّهُ ثُمَّ ٱسْتَقَٰمُوا۟ تَتَنَزَّلُ عَلَيْهِمُ ٱلْمَلَٰٓئِكَةُ أَلَّا تَخَافُوا۟ وَلَا تَحْزَنُوا۟ وَأَبْشِرُوا۟ بِٱلْجَنَّةِ ٱلَّتِى كُنتُمْ تُوعَدُونَ", transliteration: "Inna allatheena qaloo rabbuna Allahu thumma istaqamoo tatanazzalu AAalayhimu almalaikatu alla takhafoo wala tahzanoo waabshiroo bialjannati allatee kuntum tooAAadoona", transliterationB: "Innal lazeena qaaloo Rabbunal laahu summas taqaamoo tatanazzalu 'alaihimul malaaa 'ikatu allaa takhaafoo wa laa tahzanoo wa abshiroo bil Jannnatil latee kuntum too'adoon", english: "In the case of those who say, \"Our Lord is Allah\", and, further, stand straight and steadfast, the angels descend on them (from time to time): \"Fear ye not!\" (they suggest), \"Nor grieve! but receive the Glad Tidings of the Garden (of Bliss), the which ye were promised", romanUrdu: "Jin logon ne kaha ke Allah hamara Rubb hai aur phir woh ispar saabit qadam rahey, yaqeenan unpar farishtey nazil hotay hain, aur unsey kehte hain ke “na daro, na gham karo, aur khush ho jao us jannat ki basharat (khush khabri) se jiska tumse waada kiya gaya hai" },
    { number: 31, arabic: "نَحْنُ أَوْلِيَآؤُكُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَفِى ٱلْءَاخِرَةِ ۖ وَلَكُمْ فِيهَا مَا تَشْتَهِىٓ أَنفُسُكُمْ وَلَكُمْ فِيهَا مَا تَدَّعُونَ", transliteration: "Nahnu awliyaokum fee alhayati alddunya wafee alakhirati walakum feeha ma tashtahee anfusukum walakum feeha ma taddaAAoona", transliterationB: "Nahnu awliyaaa'ukum fil hayaatid dunyaa wa fil Aakhirati wa lakum feehaa maa tashtaheee anfusukum wa lakum feehaa ma tadda'oon", english: "We are your protectors in this life and in the Hereafter: therein shall ye have all that your souls shall desire; therein shall ye have all that ye ask for", romanUrdu: "Hum is duniya ki zindagi mein bhi tumhare saathi hain aur aakhirat mein bhi. Wahan jo kuch tum chahoge tumhein milega aur har cheez jiski tum tamanna karoge woh tumhari hogi" },
    { number: 32, arabic: "نُزُلًۭا مِّنْ غَفُورٍۢ رَّحِيمٍۢ", transliteration: "Nuzulan min ghafoorin raheemin", transliterationB: "Nuzulam min Ghafoorir Raheem", english: "A hospitable gift from one Oft-Forgiving, Most Merciful", romanUrdu: "Yeh hai samaan e ziyafat us hasti ki taraf se jo Gafoor aur Raheem hai”" },
    { number: 33, arabic: "وَمَنْ أَحْسَنُ قَوْلًۭا مِّمَّن دَعَآ إِلَى ٱللَّهِ وَعَمِلَ صَٰلِحًۭا وَقَالَ إِنَّنِى مِنَ ٱلْمُسْلِمِينَ", transliteration: "Waman ahsanu qawlan mimman daAAa ila Allahi waAAamila salihan waqala innanee mina almuslimeena", transliterationB: "Wa man ahsanu qawlam mimman da'aaa ilal laahi wa 'amila saalihanw wa qaala innanee minal muslimeen", english: "Who is better in speech than one who calls (men) to Allah, works righteousness, and says, \"I am of those who bow in Islam", romanUrdu: "Aur us shakhs ki baat se acchi baat aur kiski hogi jisne Allah ki taraf bulaya aur neik amal kiya aur kaha ke main musalman hoon" },
    { number: 34, arabic: "وَلَا تَسْتَوِى ٱلْحَسَنَةُ وَلَا ٱلسَّيِّئَةُ ۚ ٱدْفَعْ بِٱلَّتِى هِىَ أَحْسَنُ فَإِذَا ٱلَّذِى بَيْنَكَ وَبَيْنَهُۥ عَدَٰوَةٌۭ كَأَنَّهُۥ وَلِىٌّ حَمِيمٌۭ", transliteration: "Wala tastawee alhasanatu wala alssayyiatu idfaAA biallatee hiya ahsanu faitha allathee baynaka wabaynahu AAadawatun kaannahu waliyyun hameemun", transliterationB: "Wa laa tastawil hasanatu wa las saiyi'ah; idfa' billatee hiya ahsanu fa'izal lazee bainaka wa bainahoo 'adaawatun ka'annahoo waliyun hameem", english: "Nor can goodness and Evil be equal. Repel (Evil) with what is better: Then will he between whom and thee was hatred become as it were thy friend and intimate", romanUrdu: "[Aur aey Nabi], Neki aur badi yaksan (barabar) nahin hai, tum badi ko us neki se dafa karo jo behtareen ho, tum dekhoge ke tumhare saath jiski adawat (dushmani) padi hui thi woh jigri dost bangaya hai" },
    { number: 35, arabic: "وَمَا يُلَقَّىٰهَآ إِلَّا ٱلَّذِينَ صَبَرُوا۟ وَمَا يُلَقَّىٰهَآ إِلَّا ذُو حَظٍّ عَظِيمٍۢ", transliteration: "Wama yulaqqaha illa allatheena sabaroo wama yulaqqaha illa thoo haththin AAatheemin", transliterationB: "Wa maa yulaqqaahaaa illal lazeena sabaroo wa maa yulaqqaahaaa illaa zoo hazzin 'azeem", english: "And no one will be granted such goodness except those who exercise patience and self-restraint,- none but persons of the greatest good fortune", romanUrdu: "Yeh sifat naseeb nahin hoti magar un logon ko jo sabr karte hain, aur yeh muqaam haasil nahin hota magar un logon ko jo badey naseebey wale hain" },
    { number: 36, arabic: "وَإِمَّا يَنزَغَنَّكَ مِنَ ٱلشَّيْطَٰنِ نَزْغٌۭ فَٱسْتَعِذْ بِٱللَّهِ ۖ إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ", transliteration: "Waimma yanzaghannaka mina alshshaytani nazghun faistaAAith biAllahi innahu huwa alssameeAAu alAAaleemu", transliterationB: "Wa immaa yanzaghannaka minash Shaitaani nazghun fasta'iz billaahi innahoo Huwas Samee'ul 'Aleem", english: "And if (at any time) an incitement to discord is made to thee by the Evil One, seek refuge in Allah. He is the One Who hears and knows all things", romanUrdu: "Aur agar tum shaytan ki taraf se koi uksahat (temptation) mehsoos karo to Allah ki panaah maang lo, woh sabkuch sunta aur jaanta hai" },
    { number: 37, arabic: "وَمِنْ ءَايَٰتِهِ ٱلَّيْلُ وَٱلنَّهَارُ وَٱلشَّمْسُ وَٱلْقَمَرُ ۚ لَا تَسْجُدُوا۟ لِلشَّمْسِ وَلَا لِلْقَمَرِ وَٱسْجُدُوا۟ لِلَّهِ ٱلَّذِى خَلَقَهُنَّ إِن كُنتُمْ إِيَّاهُ تَعْبُدُونَ", transliteration: "Wamin ayatihi allaylu waalnnaharu waalshshamsu waalqamaru la tasjudoo lilshshamsi wala lilqamari waosjudoo lillahi alathee khalaqahunna in kuntum iyyahu taAAbudoona", transliterationB: "Wa min Aayaatihil lailu wannahaaru washshamsu walqamar; laa tasjudoo lishshamsi wa laa lilqamari wasjudoo lillaahil lazee khala qahunna in kuntum iyyaahu ta'budoon", english: "Among His Signs are the Night and the Day, and the Sun and the Moon. Do not prostrate to the sun and the moon, but prostrate to Allah, Who created them, if it is Him ye wish to serve", romanUrdu: "Allah ki nishaniyon mein se hain yeh raat aur din aur Suraj aur Chand. Suraj ko aur Chand ko sajda na karo balke us khuda ko sajda karo jisne unhein paida kiya hai agar fil waqaii tum usi ki ibadat karne waley ho" },
    { number: 38, arabic: "فَإِنِ ٱسْتَكْبَرُوا۟ فَٱلَّذِينَ عِندَ رَبِّكَ يُسَبِّحُونَ لَهُۥ بِٱلَّيْلِ وَٱلنَّهَارِ وَهُمْ لَا يَسْـَٔمُونَ ۩", transliteration: "Faini istakbaroo faallatheena AAinda rabbika yusabbihoona lahu biallayli waalnnahari wahum la yasamoona", transliterationB: "Fa inis-takbaroo fallazee na 'inda Rabbika yusabbihoona lahoo billaili wannnahaari wa hum laa yas'amoon", english: "But is the (Unbelievers) are arrogant, (no matter): for in the presence of thy Lord are those who celebrate His praises by night and by day. And they never flag (nor feel themselves above it)", romanUrdu: "Lekin agar yeh log guroor mein aa kar apni hi baat par adey rahein to parwah nahin, jo farishtey tere Rubb ke muqarrab hain woh shab-o-roz(night and day) uski tasbeeh kar rahey hain aur kabhi nahin thakte" },
    { number: 39, arabic: "وَمِنْ ءَايَٰتِهِۦٓ أَنَّكَ تَرَى ٱلْأَرْضَ خَٰشِعَةًۭ فَإِذَآ أَنزَلْنَا عَلَيْهَا ٱلْمَآءَ ٱهْتَزَّتْ وَرَبَتْ ۚ إِنَّ ٱلَّذِىٓ أَحْيَاهَا لَمُحْىِ ٱلْمَوْتَىٰٓ ۚ إِنَّهُۥ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ", transliteration: "Wamin ayatihi annaka tara alarda khashiAAatan faitha anzalna AAalayha almaa ihtazzat warabat inna allathee ahyaha lamuhyee almawta innahu AAala kulli shayin qadeerun", transliterationB: "Wa min Aayaatiheee annaka taral arda khaashi'atan fa izaaa anzalna 'alaihal maaa'ah tazzat wa rabat; innal lazeee ahyaahaa lamuhiyil mawtaa; innahoo 'alaa kulli shai-in Qadeer", english: "And among His Signs in this: thou seest the earth barren and desolate; but when We send down rain to it, it is stirred to life and yields increase. Truly, He Who gives life to the (dead) earth can surely give life to (men) who are dead. For He has power over all things", romanUrdu: "Aur Allah ki nishaniyon mein se ek yeh hai ke tum dekhte ho zameen sooni (barren) padi hui hai, phir joon-hi ke humne uspar paani barsaya, yakayak woh phabak uthti hai aur phool jaati hai (quivers and wells).Yakeenan jo khuda is mari (dead) hui zameen ko jila(zinda) uthata hai woh murdon ko bhi zindagi bakshne wala hai.Yaqeenan woh har cheez par qudrat rakhta hai" },
    { number: 40, arabic: "إِنَّ ٱلَّذِينَ يُلْحِدُونَ فِىٓ ءَايَٰتِنَا لَا يَخْفَوْنَ عَلَيْنَآ ۗ أَفَمَن يُلْقَىٰ فِى ٱلنَّارِ خَيْرٌ أَم مَّن يَأْتِىٓ ءَامِنًۭا يَوْمَ ٱلْقِيَٰمَةِ ۚ ٱعْمَلُوا۟ مَا شِئْتُمْ ۖ إِنَّهُۥ بِمَا تَعْمَلُونَ بَصِيرٌ", transliteration: "Inna allatheena yulhidoona fee ayatina la yakhfawna AAalayna afaman yulqa fee alnnari khayrun am man yatee aminan yawma alqiyamati iAAmaloo ma shitum innahu bima taAAmaloona baseerun", transliterationB: "Innal lazeena yulhidoona feee Aayaatina laa yakhfawna 'alainaa' afamai yulqaa fin Naari khayrun am mai yaateee aaminai Yawmal Qiyaamah; i'maloo ma shi'tum innahoo bimaa ta'maloona Baseer", english: "Those who pervert the Truth in Our Signs are not hidden from Us. Which is better?- he that is cast into the Fire, or he that comes safe through, on the Day of Judgment? Do what ye will: verily He seeth (clearly) all that ye do", romanUrdu: "Jo log hamari aayat ko ultay maani pehnatay hain (pervert Our Signs) woh humse kuch chupe huey nahin hain. Khud hi sochlo ke aaya woh shaks behtar hai jo aag mein jhonka janey wala hai ya woh jo Qayamat ke roz aman ki halat mein haazir hoga? Karte raho jo kuch tum chaho, tumhari saari harkaton ko Allah dekh raha hai" },
    { number: 41, arabic: "إِنَّ ٱلَّذِينَ كَفَرُوا۟ بِٱلذِّكْرِ لَمَّا جَآءَهُمْ ۖ وَإِنَّهُۥ لَكِتَٰبٌ عَزِيزٌۭ", transliteration: "Inna allatheena kafaroo bialththikri lamma jaahum wainnahu lakitabun AAazeezun", transliterationB: "Inna Lazeena kafaroo biz Zikri lammaa jaa'ahum wa innahoo la Kitaabun 'Azeez", english: "Those who reject the Message when it comes to them (are not hidden from Us). And indeed it is a Book of exalted power", romanUrdu: "Yeh woh log hain jinke samne kalaam-e-naseehat aaya to unhon ne isey maan-ne se inkar kardiya, magar haqeeqat yeh hai ke yeh ek zabardast kitaab hai" },
    { number: 42, arabic: "لَّا يَأْتِيهِ ٱلْبَٰطِلُ مِنۢ بَيْنِ يَدَيْهِ وَلَا مِنْ خَلْفِهِۦ ۖ تَنزِيلٌۭ مِّنْ حَكِيمٍ حَمِيدٍۢ", transliteration: "La yateehi albatilu min bayni yadayhi wala min khalfihi tanzeelun min hakeemin hameedin", transliterationB: "Laa yaateehil baatilu mim baini yadaihi wa laa min khalfihee tanzeelum min Hakeemin Hameed", english: "No falsehood can approach it from before or behind it: It is sent down by One Full of Wisdom, Worthy of all Praise", romanUrdu: "Baatil na saamne se ispar aa sakta hai na peechey se, yeh ek hakeem (most wise) o Hameed(Immensely Praiseworthy) ki nazil karda cheez hai" },
    { number: 43, arabic: "مَّا يُقَالُ لَكَ إِلَّا مَا قَدْ قِيلَ لِلرُّسُلِ مِن قَبْلِكَ ۚ إِنَّ رَبَّكَ لَذُو مَغْفِرَةٍۢ وَذُو عِقَابٍ أَلِيمٍۢ", transliteration: "Ma yuqalu laka illa ma qad qeela lilrrusuli min qablika inna rabbaka lathoo maghfiratin wathoo AAiqabin aleemin", transliterationB: "Maa yuqaalu laka illaa maa qad qeela lir Rusuli min qablik; inna Rabbaka lazoo maghfiratinw wa zoo 'iqaabin aleem", english: "Nothing is said to thee that was not said to the messengers before thee: that thy lord has at his Command (all) forgiveness as well as a most Grievous Penalty", romanUrdu: "Aey Nabi, tumse jo kuch kaha jaa raha hai usmein koi cheez bhi aisi nahin hai jo tumse pehle guzrey huey Rasoolon se na kahi jaa chuki ho. Beshak tumhara Rubb bada darguzar karne wala hai, aur uske saath badi dardnaak saza dene wala hai" },
    { number: 44, arabic: "وَلَوْ جَعَلْنَٰهُ قُرْءَانًا أَعْجَمِيًّۭا لَّقَالُوا۟ لَوْلَا فُصِّلَتْ ءَايَٰتُهُۥٓ ۖ ءَا۬عْجَمِىٌّۭ وَعَرَبِىٌّۭ ۗ قُلْ هُوَ لِلَّذِينَ ءَامَنُوا۟ هُدًۭى وَشِفَآءٌۭ ۖ وَٱلَّذِينَ لَا يُؤْمِنُونَ فِىٓ ءَاذَانِهِمْ وَقْرٌۭ وَهُوَ عَلَيْهِمْ عَمًى ۚ أُو۟لَٰٓئِكَ يُنَادَوْنَ مِن مَّكَانٍۭ بَعِيدٍۢ", transliteration: "Walaw jaAAalnahu quranan aAAjamiyyan laqaloo lawla fussilat ayatuhu aaAAjamiyyun waAAarabiyyun qul huwa lillatheena amanoo hudan washifaon waallatheena la yuminoona fee athanihim waqrun wahuwa AAalayhim AAaman olaika yunadawna min makanin baAAeedin", transliterationB: "Wa law ja'alnaahu Qur-aanan A'jamiyyal laqaaloo law laa fussilat Aayaatuhoo 'a A'jamiyyunw wa 'Arabiyy; qul huwa lillazeena aamanoo hudanw wa shifaaa'unw wallazeena la yu'minoona feee aazaanihim waqrunw wa huwa 'alaihim 'amaa; ulaaa'ika yunaadawna mim maakaanim ba'eed", english: "Had We sent this as a Qur'an (in the language) other than Arabic, they would have said: \"Why are not its verses explained in detail? What! (a Book) not in Arabic and (a Messenger an Arab?\" Say: \"It is a Guide and a Healing to those who believe; and for those who believe not, there is a deafness in their ears, and it is blindness in their (eyes): They are (as it were) being called from a place far distant", romanUrdu: "Agar hum isko ajami(non arabic) Quraan bana kar bhejte to yeh log kehte “Kyun na iski aayat khol kar bayan ki gayi? Kya ajeeb baat hai ke kalaam ajami (non-arabic) hai aur mukhatib arabi”.Insey kaho yeh quran imaan laanay walaon ke liye to hidayat aur shifaa hai, magar jo log iman nahin laatey unke liye yeh kaano ki daat (plug / behrapan) aur aankhon ki patti (covering) hai .Unka haal to aisa hai jaise unko door se pukara ja raha ho" },
    { number: 45, arabic: "وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ فَٱخْتُلِفَ فِيهِ ۗ وَلَوْلَا كَلِمَةٌۭ سَبَقَتْ مِن رَّبِّكَ لَقُضِىَ بَيْنَهُمْ ۚ وَإِنَّهُمْ لَفِى شَكٍّۢ مِّنْهُ مُرِيبٍۢ", transliteration: "Walaqad atayna moosa alkitaba faikhtulifa feehi walawla kalimatun sabaqat min rabbika laqudiya baynahum wainnahum lafee shakkin minhu mureebin", transliterationB: "Wa laqad aatainaa Moosal Kitaaba fakhtulifa fee; wa lawlaa Kalimatun sabaqat mir Rabbika laqudiya bainahum; wa innahum lafee shakkim minhu mureeb", english: "We certainly gave Moses the Book aforetime: but disputes arose therein. Had it not been for a Word that went forth before from thy Lord, (their differences) would have been settled between them: but they remained in suspicious disquieting doubt thereon", romanUrdu: "Issey pehle humne Moosa ko kitaab di thi aur uske maamle mein bhi yahi ikhtilaf hua tha. Agar tere Rubb ne pehle hi ek baat tai na kardi hoti to in ikhtilaf karne walon ke darmiyan faisla chuka diya jata, aur haqeeqat yeh hai ke yeh log uski taraf se sakht iztaraab angeiz (sakht bechain karne wale/disquieting) shakk mein paday huey hain" },
    { number: 46, arabic: "مَّنْ عَمِلَ صَٰلِحًۭا فَلِنَفْسِهِۦ ۖ وَمَنْ أَسَآءَ فَعَلَيْهَا ۗ وَمَا رَبُّكَ بِظَلَّٰمٍۢ لِّلْعَبِيدِ", transliteration: "Man AAamila salihan falinafsihi waman asaa faAAalayha wama rabbuka bithallamin lilAAabeedi", transliterationB: "Man 'amila salihan falinafshihee wa man asaaa'a fa'alaihaa; wamaa rabbuka bizallaamil lil 'abeed", english: "Whoever works righteousness benefits his own soul; whoever works evil, it is against his own soul: nor is thy Lord ever unjust (in the least) to His Servants", romanUrdu: "Jo koi neik amal karega apne hi liye accha karega, jo badi (evil) karega uska wabal usi par hoga, aur tera Rubb apne bandon ke haqq mein zaalim nahin hai" },
    { number: 47, arabic: "۞ إِلَيْهِ يُرَدُّ عِلْمُ ٱلسَّاعَةِ ۚ وَمَا تَخْرُجُ مِن ثَمَرَٰتٍۢ مِّنْ أَكْمَامِهَا وَمَا تَحْمِلُ مِنْ أُنثَىٰ وَلَا تَضَعُ إِلَّا بِعِلْمِهِۦ ۚ وَيَوْمَ يُنَادِيهِمْ أَيْنَ شُرَكَآءِى قَالُوٓا۟ ءَاذَنَّٰكَ مَا مِنَّا مِن شَهِيدٍۢ", transliteration: "Ilayhi yuraddu AAilmu alssaAAati wama takhruju min thamaratin min akmamiha wama tahmilu min ontha wala tadaAAu illa biAAilmihi wayawma yunadeehim ayna shurakaee qaloo athannaka ma minna min shaheedin", transliterationB: "Ilaihi yuraddu 'ilmus Saaa'ah; wa maa takhruju min samaraatim min akmaamihaa wa maa tahmilu min unsaa wa laa tada'u illaa bi'ilmih; wa Yawma yunaadeehim aina shurakaaa'ee qaalooo aazannaaka maa minnaa min shaheed", english: "To Him is referred the Knowledge of the Hour (of Judgment: He knows all): No date-fruit comes out of its sheath, nor does a female conceive (within her womb) nor bring forth the Day that (Allah) will propound to them the (question), \"Where are the partners (ye attributed to Me?\" They will say, \"We do assure thee not one of us can bear witness)", romanUrdu: "Us sa-ath (hour/Qayamat) ka ilm Allah hi ki taraf raajeh hota hai, wahi un saare phalon (fruits) ko jaanta hai jo apne shagufon (coverings/sheath) mein se nilakte hain, usi ko maaloom hai ke kaunsi maada (female) hamila (conceive) hui hai aur kisne baccha janaa (give birth) hai. Phir jis roz woh in logon ko pukarega ke kahan hain mere woh shareek? Yeh kahenge, “hum arz kar chuke hain, aaj hum mein se koi iski gawahi dene wala nahin hai.”" },
    { number: 48, arabic: "وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَدْعُونَ مِن قَبْلُ ۖ وَظَنُّوا۟ مَا لَهُم مِّن مَّحِيصٍۢ", transliteration: "Wadalla AAanhum ma kanoo yadAAoona min qablu wathannoo ma lahum min maheesin", transliterationB: "Wa dalla 'anhum maa kaanoo yad'oona min qablu wa zannoo maa lahum mim mahees", english: "The (deities) they used to invoke aforetime will leave them in the lurch, and they will perceive that they have no way of escape", romanUrdu: "Us waqt woh sarey maabood insey ghum ho jaayenge jinhein yeh issey pehle pukarte thay, aur yeh log samajh lenge ke inke liye ab koi jaaye panaah nahin hai" },
    { number: 49, arabic: "لَّا يَسْـَٔمُ ٱلْإِنسَٰنُ مِن دُعَآءِ ٱلْخَيْرِ وَإِن مَّسَّهُ ٱلشَّرُّ فَيَـُٔوسٌۭ قَنُوطٌۭ", transliteration: "La yasamu alinsanu min duAAai alkhayri wain massahu alshsharru fayaoosun qanootun", transliterationB: "Laa yas'amul insaanu min du'aaa'il khairi wa im massa hush sharru fa ya'oosun qanoot", english: "Man does not weary of asking for good (things), but if ill touches him, he gives up all hope (and) is lost in despair", romanUrdu: "Insaan kabhi bhalayi ki dua maangte nahin thakta, aur jab koi aafat ispar aa jaati hai to mayoos o dil shikasta ho jata hai" },
    { number: 50, arabic: "وَلَئِنْ أَذَقْنَٰهُ رَحْمَةًۭ مِّنَّا مِنۢ بَعْدِ ضَرَّآءَ مَسَّتْهُ لَيَقُولَنَّ هَٰذَا لِى وَمَآ أَظُنُّ ٱلسَّاعَةَ قَآئِمَةًۭ وَلَئِن رُّجِعْتُ إِلَىٰ رَبِّىٓ إِنَّ لِى عِندَهُۥ لَلْحُسْنَىٰ ۚ فَلَنُنَبِّئَنَّ ٱلَّذِينَ كَفَرُوا۟ بِمَا عَمِلُوا۟ وَلَنُذِيقَنَّهُم مِّنْ عَذَابٍ غَلِيظٍۢ", transliteration: "Walain athaqnahu rahmatan minna min baAAdi darraa massathu layaqoolanna hatha lee wama athunnu alssaAAata qaimatan walain rujiAAtu ila rabbee inna lee AAindahu lalhusna falanunabbianna allatheena kafaroo bima AAamiloo walanutheeqannahum min AAathabin ghaleethin", transliterationB: "Wa la in azaqnaahu rahmatam minnaa mim ba'di dar raaa'a massat hu la yaqoolanna haazaa lee wa maaa azunnus Saa'ata qaaa'imatanw wa la'in ruji'tu ilaa Rabbeee inna lee 'indahoo lalhusnaa; falanu nabbi'annal lazeena kafaroo bimaa 'amiloo wa lanuzeeqan nahum min 'azaabin ghaleez", english: "When we give him a taste of some Mercy from Ourselves, after some adversity has touched him, he is sure to say, \"This is due to my (merit): I think not that the Hour (of Judgment) will (ever) be established; but if I am brought back to my Lord, I have (much) good (stored) in His sight!\" But We will show the Unbelievers the truth of all that they did, and We shall give them the taste of a severe Penalty", romanUrdu: "Magar junhi ke sakht waqt guzar jaane ke baad hum isey apni rehmant ka mazaa chakhate hain, yeh kehta hai ke “main isi ka mustahiq hoon, aur main nahin samajhta ke qayamat kabhi aayegi, lekin agar waqai main apne Rubb ki tarf paltaya gaya to wahan bhi mazey karunga”. Halanke kufr karne walon ko laziman hum bata kar rahenge ke woh kya karke aaye hain, aur unhein hum baday gandhey azaab ka maza chakhayenge" },
    { number: 51, arabic: "وَإِذَآ أَنْعَمْنَا عَلَى ٱلْإِنسَٰنِ أَعْرَضَ وَنَـَٔا بِجَانِبِهِۦ وَإِذَا مَسَّهُ ٱلشَّرُّ فَذُو دُعَآءٍ عَرِيضٍۢ", transliteration: "Waitha anAAamna AAala alinsani aAArada wanaa bijanibihi waitha massahu alshsharru fathoo duAAain AAareedin", transliterationB: "Wa izaaa an'amnaa 'alal insaani a'rada wa na-aa bijaani bihee wa izaa massahush sharru fazoo du'aaa'in 'areed", english: "When We bestow favours on man, he turns away, and gets himself remote on his side (instead of coming to Us); and when evil seizes him, (he comes) full of prolonged prayer", romanUrdu: "Insaan ko jab hum niyamat detay hain to woh mooh pherta hai aur akad jata hai, aur jab usey koi aafat choo jaati hai to lambi chowdi duaein karne lagta hai" },
    { number: 52, arabic: "قُلْ أَرَءَيْتُمْ إِن كَانَ مِنْ عِندِ ٱللَّهِ ثُمَّ كَفَرْتُم بِهِۦ مَنْ أَضَلُّ مِمَّنْ هُوَ فِى شِقَاقٍۭ بَعِيدٍۢ", transliteration: "Qul araaytum in kana min AAindi Allahi thumma kafartum bihi man adallu mimman huwa fee shiqaqin baAAeedin", transliterationB: "Qul araiaitum in kaana min 'indil laahi summa kafar tum bihee man adallu mimman huwa fee shiqaqim ba'eed", english: "Say: \"See ye if the (Revelation) is (really) from Allah, and yet do ye reject it? Who is more astray than one who is in a schism far (from any purpose)", romanUrdu: "(Aey Nabi), insey kaho, kabhi tumne yeh bhi socha ke agar waqayi yeh Quran khuda hi ki taraf se hua aur tum iska inkar karte rahey to us shaks se badh kar bhatka hua aur kaun hoga jo iski mukhalifat mein door tak nikal gaya ho" },
    { number: 53, arabic: "سَنُرِيهِمْ ءَايَٰتِنَا فِى ٱلْءَافَاقِ وَفِىٓ أَنفُسِهِمْ حَتَّىٰ يَتَبَيَّنَ لَهُمْ أَنَّهُ ٱلْحَقُّ ۗ أَوَلَمْ يَكْفِ بِرَبِّكَ أَنَّهُۥ عَلَىٰ كُلِّ شَىْءٍۢ شَهِيدٌ", transliteration: "Sanureehim ayatina fee alafaqi wafee anfusihim hatta yatabayyana lahum annahu alhaqqu awalam yakfi birabbika annahu AAala kulli shayin shaheedun", transliterationB: "Sanureehim Aayaatinaa fil aafaaqi wa feee anfusihim hattaa yatabaiyana lahum annahul haqq; awa lam yakfi bi Rabbika annahoo 'alaa kulli shai-in Shaheed", english: "Soon will We show them our Signs in the (furthest) regions (of the earth), and in their own souls, until it becomes manifest to them that this is the Truth. Is it not enough that thy Lord doth witness all things", romanUrdu: "Anqareeb hum unko apni nishaniyan aafaq (horizons)mein bhi dikhayenge aur inke apne nafs mein bhi yahan tak-ke inpar yeh baat khul jayegi ke yeh Quran waqayi barhaqq hai, kya yeh baat kaafi nahin hai ke tera Rubb har cheez ka shahid(witness) hai" },
    { number: 54, arabic: "أَلَآ إِنَّهُمْ فِى مِرْيَةٍۢ مِّن لِّقَآءِ رَبِّهِمْ ۗ أَلَآ إِنَّهُۥ بِكُلِّ شَىْءٍۢ مُّحِيطٌۢ", transliteration: "Ala innahum fee miryatin min liqai rabbihim ala innahu bikulli shayin muheetun", transliterationB: "Alaaa innahum fee miryatim mil liqaaa'i Rabbihim; alaaa innahoo bikulli shai'im muheet", english: "Ah indeed! Are they in doubt concerning the Meeting with their Lord? Ah indeed! It is He that doth encompass all things", romanUrdu: "Aagaah raho, yeh log apne Rubb ki mulaqaat mein shakk rakhte hain. Sun rakkho woh har cheez par muheet(fully encompasses everything) hai" }
  ]
};
